const input = $input.first().json;
const body = input.body || input;
const headers = input.headers || {};
const job = body.job || {};
const secret = headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || headers['x-webhook-secret'.toLowerCase()] || '';
if (!job.id) throw new Error('job.id ontbreekt');
if (!job.contactPhone) throw new Error('job.contactPhone ontbreekt');
if (!job.scriptPreview) throw new Error('scriptPreview ontbreekt');
const callerPayload = {
  externalJobId: job.id,
  phoneNumber: job.contactPhone,
  language: job.language || 'nl',
  callerName: 'De Vree Makelaardij',
  maxDurationSeconds: Number($env.AI_CALL_MAX_DURATION_SECONDS || 900),
  mustHangUpAfterSummary: true,
  voicemailMode: $env.AI_CALL_VOICEMAIL_MODE || 'short_message_or_hangup',
  script: job.scriptPreview,
  context: job.context || {},
  resultWebhookUrl: `${$env.PLATFORM_BASE_URL || 'https://kantoor.devreemakelaardij.nl'}/api/ai/call-results`,
  resultWebhookSecret: secret
};
return [{ json: { job, callerPayload, webhookSecret: secret } }];
